        return left

    def parse_logic_or(self) -> object:
        left = self.parse_logic_and()
        if self.peek().value == '||':
            self.advance()  # consume '||'
            right = self.parse_logic_and()
            return BinaryOp('||', left, right)
        return left

    def parse_logic_and(self) -> object:
        left = self.parse_equality()
        if self.peek().value == '&&':
            self.advance()  # consume '&&'
            right = self.parse_equality()
            return BinaryOp('&&', left, right)
        return left

    def parse_equality(self) -> object:
        left = self.parse_comparison()
        if self.peek().value in ('==', '!='):
            op = self.peek().value
            self.advance()  # consume operator
            right = self.parse_comparison()
            return BinaryOp(op, left, right)
        return left

    def parse_comparison(self) -> object:
        left = self.parse_term()
        if self.peek().value in ('<', '>', '<=', '>='):
            op = self.peek().value
            self.advance()  # consume operator
            right = self.parse_term()
            return BinaryOp(op, left, right)
        return left

    def parse_term(self) -> object:
        left = self.parse_factor()
        if self.peek().value in ('+', '-'):
            op = self.peek().value
            self.advance()  # consume operator
            right = self.parse_factor()
            return BinaryOp(op, left, right)
        return left

    def parse_factor(self) -> object:
        left = self.parse_unary()
        if self.peek().value in ('*', '/', '%'):
            op = self.peek().value
            self.advance()  # consume operator
            right = self.parse_unary()
            return BinaryOp(op, left, right)
        return left

    def parse_unary(self) -> object:
        if self.peek().value in ('!', '-'):
            op = self.peek().value
            self.advance()  # consume operator
            operand = self.parse_unary()
            return UnaryOp(op, operand)
        return self.parse_call()

    def parse_call(self) -> object:
        left = self.parse_primary()
        while self.peek().value in ('(', '['):
            if self.peek().value == '(':
                self.advance()  # consume '('
                args = self.parse_args()
                self.consume(')', "Expected ')' after function call")
                left = Call(left, args)
            elif self.peek().value == '[':
                self.advance()  # consume '['
                key = self.parse_expression()
                self.consume(']', "Expected ']' after index")
                left = Index(left, key)
        return left

    def parse_primary(self) -> object:
        token = self.peek()
        if token.kind == 'NUMBER':
            self.advance()
            return NumberLit(token.value)
        elif token.kind == 'STRING':
            self.advance()
            return StringLit(token.value)
        elif token.kind == 'KEYWORD':
            if token.value == 'true':
                self.advance()
                return BoolLit(True)
            elif token.value == 'false':
                self.advance()
                return BoolLit(False)
            elif token.value == 'nil':
                self.advance()
                return NilLit()
        elif token.kind == 'IDENT':
            self.advance()
            return Identifier(token.value)
        elif token.value == '(':
            self.advance()  # consume '('
            expr = self.parse_expression()
            self.consume(')', "Expected ')' after expression")
            return expr
        elif token.value == '[':
            return self.parse_list_lit()
        elif token.value == '{':
            return self.parse_dict_lit()
        elif token.value == 'fn':
            return self.parse_fn_lit()
        else:
            raise ParseError(f"Unexpected token: {token.value}", token.line, token.col)

