            if self.peek().value == '(':
                self.advance()  # consume '('
                args = self.parse_args()
                self.consume(')', "Expected ')' after function call")
                left = Call(left, args)
            elif self.peek().value == '[':
                self.advance()  # consume '['
                key = self.parse_expression()
                self.consume(']', "Expected ']' after index")
                left = Index(left, key)
        return left

    def parse_primary(self) -> object:
        token = self.peek()
        if token.kind == 'NUMBER':
            self.advance()
            return NumberLit(token.value)
        elif token.kind == 'STRING':
            self.advance()
            return StringLit(token.value)
        elif token.kind == 'KEYWORD':
            if token.value == 'true':
                self.advance()
                return BoolLit(True)
            elif token.value == 'false':
                self.advance()
                return BoolLit(False)
            elif token.value == 'nil':
                self.advance()
                return NilLit()
        elif token.kind == 'IDENT':
            self.advance()
            return Identifier(token.value)
        elif token.value == '(':
            self.advance()  # consume '('
            expr = self.parse_expression()
            self.consume(')', "Expected ')' after expression")
            return expr
        elif token.value == '[':
            return self.parse_list_lit()
        elif token.value == '{':
            return self.parse_dict_lit()
        elif token.value == 'fn':
            return self.parse_fn_lit()
        else:
            raise ParseError(f"Unexpected token: {token.value}", token.line, token.col)

    def parse_list_lit(self) -> ListLit:
        self.consume('[', "Expected '[' for list literal")
        items = []
        if self.peek().value != ']':
            while True:
                item = self.parse_expression()
                items.append(item)
                if self.peek().value != ',':
                    break
                self.advance()  # consume ','
        self.consume(']', "Expected ']' for list literal")
        return ListLit(items)

    def parse_dict_lit(self) -> DictLit:
        self.consume('{', "Expected '{' for dict literal")
        pairs = []
        if self.peek().value != '}':
            while True:
                key = self.parse_expression()
                self.consume(':', "Expected ':' in dict literal")
                value = self.parse_expression()
                pairs.append((key, value))
                if self.peek().value != ',':
                    break
                self.advance()  # consume ','
        self.consume('}', "Expected '}' for dict literal")
        return DictLit(pairs)

    def parse_fn_lit(self) -> FnLit:
        self.consume('fn', "Expected 'fn' for function literal")
        self.consume('(', "Expected '(' for function literal")
        params = self.parse_params()
        self.consume(')', "Expected ')' for function literal")
        body = self.parse_block()
        return FnLit(params, body)

    def parse_args(self) -> List[object]:
        args = []
        if self.peek().value != ')':
            while True:
                arg = self.parse_expression()
                args.append(arg)
                if self.peek().value != ',':
                    break
                self.advance()  # consume ','
        return args

def parse(source_or_tokens: Union[str, List[Token]]) -> Program:
    """Parse tinylang source into an AST Program."""
    if isinstance(source_or_tokens, str):
        tokens = tokenize(source_or_tokens)
    else:
        tokens = source_or_tokens

    parser = Parser(tokens)
    return parser.parse_program()

